const openWhatsApp = () => window.open(`https://wa.me/${WA_NUMBER}?text=${WA_MSG}`, "_blank");

function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.1 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function Reveal({ children, className = "", delay = 0, from = "bottom" }) {
  const [ref, vis] = useReveal();
  const t = { bottom:"translateY(40px)", left:"translateX(-40px)", right:"translateX(40px)", none:"none" };
  return (
    <div ref={ref} className={className} style={{
      opacity: vis ? 1 : 0,
      transform: vis ? "translate(0)" : t[from],
      transition: `opacity 0.75s ease ${delay}s, transform 0.75s cubic-bezier(.22,.68,0,1.2) ${delay}s`,
    }}>{children}</div>
  );
}

